function wpbp_count_block_types( string $html ): array {
    $counts     = array();
    $processor  = new WP_Block_Processor( $html );
    while ( $block = $processor->extract_full_block_and_advance() ) {
        $name = $block->block_name;
        if ( ! $name || $name === 'core/freeform' ) {
            continue;
        }
        $counts[ $name ] = ($counts[ $name ] ?? 0) + 1;
        if ( ! empty( $block->inner_html ) ) {
            foreach ( wpbp_count_block_types( $block->inner_html ) as $k => $v ) {
                $counts[ $k ] = ($counts[ $k ] ?? 0) + $v;
            }
        }
    }
    return $counts;
}
